import React, { useState } from 'react';
import { EmptyState, Layout, Page } from '@shopify/polaris';
import { ResourcePicker, TitleBar } from '@shopify/app-bridge-react';
import { useMutation } from '@apollo/react-hooks';
import gql from 'graphql-tag';
import store from 'store-js';
import ProductList from '../components/ProductList';


const DISCOUNT_CODE = gql`
 mutation basicCodeDiscount() {
    basicCodeDiscount() {
    startsAt: 2021-03-05T19:34:35.948Z,
    endsAt: null,
    usageLimit: null,
    appliesOncePerCustomer: false,
    title: WWFEDXGS9RVZ,
    code: WWFEDXGS9RVZ,
    minimumRequirement {
      quantity {
        greaterThanOrEqualToQuantity: null
      },
      subtotal {
        greaterThanOrEqualToSubtotal: null
      }
    },
    customerGets {
      value {
        percentage: 0.2
      },
      items {
        all: true,
        products: null,
        collections: null
      }
    },
    customerSelection {
      all: true,
      customerSavedSearches: null,
      customers: null
    }
   }
  }
`;

function Index() {
    const [makeDiscount, { data }] = useMutation(ADD_TODO);
    return (
        <Page>
            <TitleBar
                primaryAction={{
                    content: 'Select New Products',
                    onAction: () => setModal({ open: true })
                }}
            />
        </Page>
    )

}

export default Index;
